  -- 1. Function that deletes expired rows
  CREATE OR REPLACE FUNCTION public.delete_expired_audit_logs()
  RETURNS void
  LANGUAGE sql
  SECURITY DEFINER
  SET search_path = public
  AS $$
    DELETE FROM public.audit_logs
    WHERE created_at < now() - INTERVAL '3 months';
  $$;

  -- 2. Schedule the function to run once a day using pg_cron (Safely handled if extension not enabled)
  DO $$
  BEGIN
    CREATE EXTENSION IF NOT EXISTS pg_cron;
    PERFORM cron.schedule(
      'delete-expired-audit-logs',   -- job name (unique)
      '0 3 * * *',                   -- every day at 3 AM UTC
      'SELECT public.delete_expired_audit_logs();'
    );
  EXCEPTION
    WHEN OTHERS THEN
      RAISE NOTICE 'pg_cron not available or schedule failed, skipping cron setup: %', SQLERRM;
  END $$;


