  CREATE VIEW public.queue_public
  WITH (security_invoker = true)
  AS
  SELECT
    w.id,
    w.queue_number,
    split_part(coalesce(w.customer_name, 'Guest'), ' ', 1) AS first_name,
    w.status,
    w.created_at,
    w.served_at,
    w.service_id,
    COALESCE(s.duration_minutes, 30) AS duration_minutes
  FROM public.walk_ins w
  LEFT JOIN public.services s ON s.id = w.service_id
  WHERE (w.created_at AT TIME ZONE 'UTC')::date = (now() AT TIME ZONE 'UTC')::date
    AND w.status IN ('waiting', 'in_progress');

  GRANT SELECT ON public.queue_public TO anon, authenticated;

  -- Allow authenticated users to see their own walk_ins row
  DO $$
  BEGIN
    IF NOT EXISTS (
      SELECT 1 FROM pg_policies
      WHERE schemaname = 'public' AND tablename = 'walk_ins' AND policyname = 'Users can view their own walk_ins'
    ) THEN
      CREATE POLICY "Users can view their own walk_ins"
      ON public.walk_ins FOR SELECT
      TO authenticated
      USING (auth.uid() = user_id);
    END IF;
  END $$;


  -- ====================================================================================
  -- MIGRATION 13: 20260703091626_14517786-d83d-4b1e-bf4a-6ba812d8caa6.sql
  -- ====================================================================================

  DROP POLICY IF EXISTS "anon read today queue" ON public.walk_ins;
  DROP POLICY IF EXISTS "auth read today queue" ON public.walk_ins;


  -- ====================================================================================
  -- MIGRATION 14: 20260704055959_fc17cc90-bcc3-4e13-8578-28049d7ef44e.sql
  -- ====================================================================================

  -- Recreate queue_public as a SECURITY DEFINER view so anon/authenticated
  -- can read the safe today's-queue projection without needing per-row RLS
  -- or column-level grants on public.walk_ins.
  DROP VIEW IF EXISTS public.queue_public;

  CREATE VIEW public.queue_public
  WITH (security_invoker = false) AS
  SELECT
    w.id,
    w.queue_number,
    split_part(coalesce(w.customer_name, ''), ' ', 1) AS first_name,
    w.status,
    w.created_at,
    w.served_at,
    w.service_id,
    COALESCE(s.duration_minutes, 30) AS duration_minutes
  FROM public.walk_ins w
  LEFT JOIN public.services s ON s.id = w.service_id
  WHERE (w.created_at AT TIME ZONE 'UTC')::date = (now() AT TIME ZONE 'UTC')::date
    AND w.status IN ('waiting', 'in_progress');

  GRANT SELECT ON public.queue_public TO anon, authenticated;

  -- ====================================================================================
  -- MIGRATION 15: 20260704194500_create_reviews.sql
  -- ====================================================================================

  CREATE TABLE IF NOT EXISTS public.reviews (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    booking_id UUID REFERENCES public.bookings(id) ON DELETE SET NULL,
    customer_name TEXT NOT NULL,
    service_name TEXT NOT NULL,
    rating INTEGER NOT NULL CHECK (rating >= 1 AND rating <= 5),
    comment TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
  );

  GRANT SELECT, INSERT ON public.reviews TO anon, authenticated;
  GRANT ALL ON public.reviews TO service_role;
  ALTER TABLE public.reviews ENABLE ROW LEVEL SECURITY;

  DROP POLICY IF EXISTS "Anyone can read reviews" ON public.reviews;
  CREATE POLICY "Anyone can read reviews" ON public.reviews FOR SELECT TO anon, authenticated USING (true);

  DROP POLICY IF EXISTS "Anyone can insert reviews" ON public.reviews;
  CREATE POLICY "Anyone can insert reviews" ON public.reviews FOR INSERT TO anon, authenticated WITH CHECK (true);

